%%
%[text] ## Text Formatting
%[text] 
%[text] ### Font
%[text] a\[\\bfb\]c = 굵게 
%[text] \\fontname{times} = times font로
%[text] a{\\itb}c = italic체
%[text] \\fontsize{12} = font size 12
%[text] \\ita{\\rmb}c = 정자체
%[text] 
%[text] ### Subscript and Superscript
%[text] A^{2-x}+b\_1 
%%
%light intensity
d = 10 : 0.1 : 22; % 이론치
dd = 10 : 2 : 22; % 실험치

y = 1000 * exp (-0.15 * (d - 10));
yy = 1000 * exp (-0.16 * (dd - 10));

h = plot(d, y, 'b-', dd, yy, 'r-o'); %이론 실선 파랑 / 실험 대시 빨강 %[output:8854a93c]
axis ([8 24 0 1200]); %[output:8854a93c]

set(h(1), 'LineWidth', 2); % 이론 %[output:8854a93c]
set(h(2), 'LineWidth', 2); % 실험 %[output:8854a93c]
xlabel('Distance (cm)'); %[output:8854a93c]
ylabel("Intensity (lux)"); %[output:8854a93c]
title('Light Imtensity as a Function of Distance'); %[output:8854a93c]
legend('Theory', 'Experiment'); % 이론 실험 %[output:8854a93c]
grid; %[output:8854a93c]
%%
%[text] ## Mission 3
%light intensity
d = 10 : 0.1 : 22; % 이론치
dd = 10 : 2 : 22; % 실험치

y = 1000 * exp (-0.15 * (d - 10));
yy = 1000 * exp (-0.16 * (dd - 10));

h = plot(d, y, 'b-', dd, yy, 'r-o'); %이론 실선 파랑 / 실험 대시 빨강
axis ([8 24 0 1200]);

set(h(1), 'LineWidth', 2); % 이론
set(h(2), 'LineWidth', 2); % 실험
xlabel('Distance (cm)');
ylabel("Intensity (lux)");
title('Light Imtensity as a Function of Distance');
legend('Theory', 'Experiment'); % 이론 실험
grid;
